async function adjustUserPoints(walletAddress, pointsChange, reason) {
  const db = await getDb();
  if (!db) {
    throw new Error("Database not available");
  }
  const profile = await getWalletProfile(walletAddress);
  if (!profile) {
    return { success: false, newTotal: 0, message: "Wallet profile not found" };
  }
  const newTotal = Math.max(0, profile.totalPoints + pointsChange);
  await db.update(walletProfiles).set({ totalPoints: newTotal }).where(eq(walletProfiles.walletAddress, walletAddress));
  await db.insert(pointsHistory).values({
    walletAddress,
    transactionType: "admin_adjustment",
    pointsChange,
    balanceAfter: newTotal,
    description: `Admin adjustment: ${reason}`
  });
  return {
    success: true,
    newTotal,
    message: `Points adjusted by ${pointsChange}. New total: ${newTotal}`
  };
}

